  insert into projects (id, org_id, name, disc_export) values
    ('prd-fathering-excellence', v_org, 'Fathering Excellence Profile', false),
    ('prd-reqpub-platform', v_org, 'ReqPub Platform', false);
insert into project_fields (project_id, field_id, value, rev, updated_by_name, updated_at) values
  ('prd-fathering-excellence', 'ctrl_product', '"Fathering Excellence Profile"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ctrl_org', '"Collection Ventures"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ctrl_owner', '"Micah Canfield"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ctrl_status', '"In Review"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_purpose', '"This document is the authoritative requirements record for the Fathers.com continuing-education and community platform. It is written for the build team (PM, CTO, SWE leads) and the build agent, and it defines the vision, roles, experiences, architecture, data model, engagement mechanics, institutional deployment modes, and the phased build plan. Where this record is silent, the build escalates to the owner rather than inventing scope."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_vision', '"Make Fathers.com the number-one global platform where fathers assess where they stand, grow with proven material, lock arms with other men, and prove their progress in ways courts, employers, and their own families can trust. The founding belief, unchanged since 1990: when fathers grow, children flourish. North Star: Weekly Active Fathering Actions (WAFA), the count of fathers who log at least one intentional real-world fathering action in a given week. Business North Star: Verified Completions, the unit institutions pay for."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_problem', '"Fathers lack a trusted way to know where they stand and prove progress. Roughly one in four US children live without a father in the home. Generic parenting apps measure screen time, not fathering, and produce nothing a court, employer, or parole board will accept. The opportunity is a validated instrument plus a proof rail plus real-world brotherhood, three things AI cannot commoditize and men will actually pay for."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_market', '"About 34.3 million US men have a biological child under 18, within roughly 71 million North American fathers. The client segmentation places about 56 percent of fathers as growth-oriented and 44 percent as at-risk across five segments. Institutional buyers already fund fatherhood programming: corrections, courts, employers, and military and VA channels. The first deployment is free for a 100,000-subscriber onboarding wave, with monetization following immediately."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'context', '"Mobile-first installable PWA at 390-point width, one primary action per screen. Corrections mode must run fully offline for a class session and sync when connectivity returns. Institutional modes (employer, court, corrections, military) are configuration bundles over one platform, not separate apps. Assessment must never block on the network; the member is the only thing it waits on."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_solution', '"One platform with a single spine: a validated onboarding assessment (the Keystone Father Profile) that tells every man the truth, a deterministic plan engine that maps his lowest factors to exact modules, region-and-stage-matched Crews of 5 to 8 men with an accountability Anchor, cohort Expeditions that end in a verified completion, a weekly Rhythm of logged real-world actions, a verified-behavior rank ladder (Waypoints), and a signing-and-verification layer (ProofRail) whose records verify independently even if Fathers.com is offline."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'staged', '"Yes"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'has_ai', '"Yes"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'golden', '"Voice mode is evaluated against a human-labeled set of colloquial answers mapped to the 1-to-5 scale, built during the pilot and stratified by dialect cohort. The knowledge agent is evaluated against a probe set of in-corpus and out-of-corpus questions; every generated response must cite a source module, and out-of-corpus probes must trigger honest deferral plus a content-gap ticket, never an improvised answer."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'vulnerable', '"Yes"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'safeguard', '"A disclosure of self-harm, harm to others, or domestic violence routes to a trained human within one hour, pauses all gamification and nudges for that member, and surfaces professional resources in-product. The protocol is never punitive and never automated therapy (runbook RB-04, interaction IX-09). Minors are excluded from the platform in every role; child records are life-stage and birth-year band only."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'consent', '"Research, comparison (self vs observer), and marketing consents are separate records, plain-language, opt-in, and revocable at any time. Research consent is separate from terms acceptance. The self-versus-observer comparison overlay renders only after both the father and the secondary participant accept an identical consent sheet; either revocation removes it immediately."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'retention', '"Responses and scores are retained while the account lives. Self-serve export (JSON plus PDFs) and account deletion carry a 14-day cooldown; deletion cascades per the retention matrix, with certificates preserved as anonymized verification stubs so previously issued proofs still verify. Corrections records follow the facility agreement and applicable records law. The audit log is retained seven years."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'residency', '"Primary data is stored and processed in the platform region on the managed Postgres backend. Cross-border processing for institutional channels is contracted per agreement. Voice audio is processed for transcription and discarded by default; transcripts store with the response record."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'access', '"Row-level security defaults to deny. Members read their own rows; Crew and group visibility flow through membership joins. Assessment scores carry the strictest policy: readable by the member, the scoring service, and consented case access only, and are never visible to employers, courts, corrections officials, or military admins. Institutional roles read only aggregate views with a minimum cohort size of ten. Staff access is scoped by case and logged; production access is break-glass and reviewed monthly."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'verify_note', '"A release is accepted when every Must requirement for the phase passes its fit criterion in production, the RLS default-deny suite passes, and the phase exit criteria in the build plan hold. ProofRail records must verify independently of Fathers.com systems (the Mars rule) with zero false-valids."'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'link_repo', '"to confirm"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'link_board', '"to confirm"'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'link_design', '"to confirm"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ctrl_product', '"ReqPub Platform"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ctrl_org', '"Collection Ventures"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ctrl_owner', '"Micah Canfield"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ctrl_status', '"In Review"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ov_purpose', '"This document is the working requirements record for ReqPub itself: the platform the team uses to turn discovery into a versioned, approved, testable requirements record. It states what has already shipped (so the team edits from reality) and what remains for the next phase (SOC 2 Type II and e-signature execution with cryptographic sealing). It is the record the team stress-tests the platform against."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ov_vision', '"The requirements record your client approves. ReqPub takes a project from discovery to an approved, testable baseline where every version is numbered, every approval is named, and every export carries its own history. When someone asks what was agreed, you open the record. The terminal promise is a sign-off that is cryptographically sealed to the exact baseline signed, so the document proves itself."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ov_problem', '"Projects fail at \"that’s not what we agreed,\" not at the build. Requirements live in decks, documents, and email threads; reconstructing who approved what, when, and what changed since the client last saw it burns senior hours and goodwill. Teams need a single record that moves with the scope and defends itself under review."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'ov_market', '"Advisory and product teams whose work is reviewed, contested, and approved: consulting engagement teams, agencies, and internal product groups working with external subject-matter experts and partners. The buyer answers to a client and to procurement; the record is the artifact both trust."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'context', '"A static frontend (installable, no build step) on a managed Postgres backend with row-level security, realtime, and edge functions. Deployed on GitHub Pages against Supabase. Used live by internal teams (managers and viewers), external SMEs with no account (tokened links), and partners who manage SMEs (a portal). Multiplayer editing must survive nine or more concurrent editors without lost writes."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'sol_solution', '"A relational requirements platform: every shared structure is rows, not a JSON blob, so concurrent adds cannot overwrite each other; every scalar field carries a revision so stale writes are detected and resolved rather than clobbered; version numbers are allocated server-side; approvals are a real state machine with named, server-stamped sign-off; sharing is section-scoped and brand-carrying; and every export carries its own history on the cover. The next phase seals that export cryptographically and executes sign-off by e-signature."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'staged', '"Yes"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'has_ai', '"No"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'vulnerable', '"No"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'consent', '"External reviewers (SMEs) act through tokened links with no account; they see only the curated, section-scoped brief the team publishes, never fit criteria, schedules, or internal notes. Partners see only the published brief of projects granted to them. All external participation is on the record with names and timestamps."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'retention', '"Every project, version, comment, and approval is retained for the life of the workspace. Versions are immutable baselines. The activity log is append-only and written by the database itself. Managers can archive a project; an administrator can restore it. Export to Word, PDF, and Markdown is available at any time."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'residency', '"Data is stored and processed in the Supabase project region. The public anon key ships in the client by design; all protection rests on row-level security and the rev-checked RPCs."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'access', '"Row-level security scopes every table to the organization. Managers write; viewers read everything and reply in threads; partners reach only assigned projects through the portal; SMEs reach only tokened briefs. Worksheet fields and rows are writable only through rev-checked SECURITY DEFINER RPCs; write is revoked from the audit-only tables. Approval provenance is stamped from the signed-in user and cannot be forged."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'verify_note', '"A capability is accepted when it passes its fit criterion in production and is covered by the automated suite (33 unit tests, 79 backend checks on a real Postgres). The SOC 2 and e-signature requirements are accepted only when independently audited and, for e-signature, when a sealed export verifies against its exact baseline."'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'link_repo', '"github.com/StrategyandDesign/ReqPub"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'link_board', '"to confirm"'::jsonb, 1, 'Seed', now()),
  ('prd-reqpub-platform', 'link_design', '"reqpub.com"'::jsonb, 1, 'Seed', now())
insert into field_rows (project_id, field_id, k, data, pos, updated_by_name, updated_at) values
  ('prd-fathering-excellence', 'ov_goals', 1, '{"text":"Grow Weekly Active Fathering Actions (WAFA) week over week as the primary mission metric."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_goals', 2, '{"text":"Produce Verified Completions (assessments, Expeditions, courses) as the fundable business unit, reported weekly by channel."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_goals', 3, '{"text":"Onboard the 100,000-subscriber wave with assessment completion at or above 75 percent of starters."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_goals', 4, '{"text":"Reach Crew join at or above 40 percent of new completers and week-4 Rhythm at or above 45 percent."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'ov_goals', 5, '{"text":"Sign at least one institutional channel (employer, court, corrections, or military) with real revenue."}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 1, '{"text":"Instrument-agnostic assessment engine that loads the Keystone Father Profile as configuration and runs multi-session, resumable, autosaving intake."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 2, '{"text":"Deterministic personalization engine mapping factor bands and child life-stage to an ordered plan of three active items."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 3, '{"text":"Crews, Anchors, and leader-run groups with Crew-scoped and Anchor-scoped messaging only."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 4, '{"text":"Weekly Rhythm logging, cohort Expeditions, and a verified-behavior Waypoints rank ladder."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 5, '{"text":"ProofRail signing, timestamping, transparency log, and public certificate verification."}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 6, '{"text":"Four institutional deployment modes: employer, court, corrections (offline-capable), and military."}'::jsonb, 6, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_in', 7, '{"text":"Eyes-free voice assessment (later phase) and a grounded knowledge agent behind the plan (later phase)."}'::jsonb, 7, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 1, '{"text":"No infinite-scroll feed; the home screen is a mission board."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 2, '{"text":"No minor accounts and no collection of children’s names, ever."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 3, '{"text":"No open direct messages between strangers; messaging is Crew and Anchor scoped."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 4, '{"text":"No daily platform-wide streak; the Rhythm is weekly, daily cadence only inside Expeditions."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 5, '{"text":"No therapy-speak, clinical claims, or diagnosis; the platform educates and connects, it does not treat."}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 6, '{"text":"No dark patterns, no ads, no selling member data, no crypto or tokens."}'::jsonb, 6, 'Seed', now()),
  ('prd-fathering-excellence', 'sol_out', 7, '{"text":"No chatbot as the front door and no native livestream infrastructure before leader demand proves it."}'::jsonb, 7, 'Seed', now()),
