  ('prd-fathering-excellence', 'assume', 2, '{"text":"The 100,000-subscriber onboarding wave exists and converts a meaningful fraction to accounts across the launch arc."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'assume', 3, '{"text":"Institutional buyers pay for verified completion and aggregate reporting, not for assessment scores."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'depend', 1, '{"text":"Managed Postgres backend (Supabase-class) with row-level security, realtime, storage, and edge functions."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'depend', 2, '{"text":"Managed video platform for on-demand modules and embedded third-party livestreams at launch."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'depend', 3, '{"text":"Payment processor with subscription billing, checkout, marketplace payouts, and tax."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'depend', 4, '{"text":"ProofRail verification service shared with the studio’s existing verification work."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'depend', 5, '{"text":"Instrument owner sign-off for any change to scoring, norms, or item structure."}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'constrain', 1, '{"text":"One deployment, domain-modular; no microservices at this audience scale."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'constrain', 2, '{"text":"The instrument is configuration; zero instrument logic in code."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'constrain', 3, '{"text":"All working names ship behind config flags for owner rename without code change."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'constrain', 4, '{"text":"WCAG 2.1 AA and Section 508 globally, because federal channels require it."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'constrain', 5, '{"text":"Answer-save p95 under 300 ms; the UI never blocks on the network."}'::jsonb, 5, 'Seed', now()),
