  ('prd-fathering-excellence', 'seg', 3, '{"segment":"Crisis-window fathers","share":"High value","desc":"Separation or custody proceedings; need a court-accepted course with proof, fast."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'seg', 4, '{"segment":"Institutional cohorts","share":"Funded","desc":"Employer, court, corrections, and military buyers who pay for verified completion."}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'persona', 1, '{"persona":"The Busy Professional","needs":"Multi-session, one-handed mobile, resumable; weekly not daily cadence."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'persona', 2, '{"persona":"The Auditory Learner","needs":"Voice assessment and audio-first modules for the commute."}'::jsonb, 2, 'Seed', now()),
