  ('prd-fathering-excellence', 'release', 6, '{"rel":"Phase Institutions B","obj":"Corrections offline mode and Reentry Bridge; military mode; outcome instrumentation for evaluation.","mvp":"to confirm","ship":"to confirm"}'::jsonb, 6, 'Seed', now()),
