  ('prd-fathering-excellence', 'release', 8, '{"rel":"Phase Guide","obj":"Grounded knowledge agent behind the plan with mandatory citations and gap tickets.","mvp":"to confirm","ship":"to confirm"}'::jsonb, 8, 'Seed', now()),
  ('prd-fathering-excellence', 'components', 1, '{"name":"Assessment Engine","owner":"Erik Companhone","status":"Planned","desc":"Instrument-agnostic, multi-session, resumable, idempotent write path."}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'components', 2, '{"name":"Plan Engine","owner":"Erik Companhone","status":"Planned","desc":"Deterministic factor-to-module mapping; three active items maximum."}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'components', 3, '{"name":"Community","owner":"Huy Tran","status":"Planned","desc":"Crews, Anchors, groups, threads, moderation, safeguarding."}'::jsonb, 3, 'Seed', now()),
