  ('prd-fathering-excellence', 'components', 7, '{"name":"Voice Mode","owner":"Erik Companhone","status":"Planned","desc":"Streaming STT, grounded intent, streaming TTS; tap parity always."}'::jsonb, 7, 'Seed', now()),
  ('prd-fathering-excellence', 'components', 8, '{"name":"Knowledge Agent","owner":"Erik Companhone","status":"Planned","desc":"Retrieval over the vetted corpus; cited generation; no unvetted claims."}'::jsonb, 8, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 1, '{"metric":"Answer-save latency","target":"p95 under 300 ms","method":"Server-acknowledged timing on the responses write path."}'::jsonb, 1, 'Seed', now()),
