  ('prd-fathering-excellence', 'metrics', 3, '{"metric":"Crew join rate (new completers)","target":"at or above 40%","method":"Crew joins within 7 days of results."}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'metrics', 4, '{"metric":"Week-4 Rhythm rate","target":"at or above 45%","method":"Members logging in week 4 of membership."}'::jsonb, 4, 'Seed', now()),
