  ('prd-fathering-excellence', 'data_entities', 3, '{"entity":"Assessment responses and scores","sens":"Personal and sensitive; strictest RLS"}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'data_entities', 4, '{"entity":"Consents (research, comparison, marketing)","sens":"Personal; separate revocable records"}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'data_entities', 5, '{"entity":"Certificates and verification records","sens":"Personal; public verify exposes initials and compliance only"}'::jsonb, 5, 'Seed', now()),
  ('prd-fathering-excellence', 'data_entities', 6, '{"entity":"Crisis and moderation cases","sens":"Sensitive; trained-human access only"}'::jsonb, 6, 'Seed', now()),
  ('prd-fathering-excellence', 'interfaces', 1, '{"iface":"Identity (SSO)","req":"SAML and OIDC with SCIM for employer seat provisioning","fit":"Employer members claim seats via SSO; the aggregate wall applies from the first screen.","comp":"Institutional Modes"}'::jsonb, 1, 'Seed', now()),
  ('prd-fathering-excellence', 'interfaces', 2, '{"iface":"Payments","req":"Subscription billing, course and store checkout, marketplace payouts, tax","fit":"Membership, courses, store, and leader payouts transact through the processor.","comp":"Community"}'::jsonb, 2, 'Seed', now()),
  ('prd-fathering-excellence', 'interfaces', 3, '{"iface":"Media platform","req":"On-demand module delivery and embedded third-party livestreams at launch","fit":"The app never proxies video bytes. Inspection.","comp":"Community"}'::jsonb, 3, 'Seed', now()),
  ('prd-fathering-excellence', 'interfaces', 4, '{"iface":"ProofRail verification service","req":"Signing, timestamping, transparency log, revocation, public verify endpoint","fit":"Certificates verify independently of the platform. Test.","comp":"ProofRail"}'::jsonb, 4, 'Seed', now()),
  ('prd-fathering-excellence', 'interfaces', 5, '{"iface":"Court verification","req":"Public code and QR verification returning course, seat-time compliance, and issue date only","fit":"A coordinator verifies with no account and no member data beyond the certificate.","comp":"Institutional Modes"}'::jsonb, 5, 'Seed', now()),
